const SHARED_PANTRY_KEY = "manzshop_pantry_id_v3";
const ORDER_INDEX_KEY = "mo3_idx";
const orderItemKey = (id) => `mo3_${id}`;
// Можно вписать свой pantryId с getpantry.cloud вручную (если уже есть):
const HARDCODED_PANTRY_ID = "";

// --- KV helpers (keyvalue.immanuel.co) ---
const kvGetString = async (key) => {
  const base = `https://keyvalue.immanuel.co/api/KeyVal/GetValue/manzshopby/${encodeURIComponent(String(key))}`;
  const urls = [
    base,
    `https://corsproxy.io/?${encodeURIComponent(base)}`,
    `https://api.allorigins.win/raw?url=${encodeURIComponent(base)}`,
  ];
  for (const url of urls) {
    try {
      const r = await fetch(url, { cache: "no-store", mode: "cors" });
      if (!r.ok) continue;
      let text = (await r.text()) || "";
      // allorigins/corsproxy иногда оборачивают в кавычки
      text = text.replace(/^"|"$/g, "").trim();
      if (text && text !== "null" && text !== "undefined" && text.length > 0) return text;
    } catch (e) {}
  }
  return null;
};

const kvSetString = async (key, value) => {
  const raw = String(value);
  if (raw.length > 1500) {
    console.warn("[KV] value too long", key, raw.length);
    return false;
  }
  const base =
    `https://keyvalue.immanuel.co/api/KeyVal/UpdateValue/manzshopby/` +
    `${encodeURIComponent(String(key))}/${encodeURIComponent(raw)}`;

  // 1) GET — без CORS-preflight
  try {
    const r = await fetch(base, { method: "GET", mode: "cors", cache: "no-store" });
    if (r.ok) return true;
  } catch (e) {}

  // 2) Image-beacon GET
  try {
    if (typeof Image !== "undefined") {
      await new Promise((resolve) => {
        const img = new Image();
        let done = false;
        const finish = () => {
          if (done) return;
          done = true;
          resolve();
        };
        img.onload = finish;
        img.onerror = finish;
        img.src = base;
        setTimeout(finish, 2000);
      });
      return true;
    }
  } catch (e) {}

  // 3) POST + proxies
  for (const url of [base, `https://corsproxy.io/?${encodeURIComponent(base)}`]) {
    try {
      const r = await fetch(url, { method: "POST", mode: "cors", cache: "no-store" });
      if (r.ok) return true;
    } catch (e) {}
  }
  return false;
};

const ensurePantryId = async () => {
  if (HARDCODED_PANTRY_ID) return HARDCODED_PANTRY_ID;

  const remote = await kvGetString(SHARED_PANTRY_KEY);
  if (remote && remote.length > 8) {
    try {
      if (typeof localStorage !== "undefined") localStorage.setItem("krost_pantry_id", remote);
    } catch (e) {}
    return remote;
  }

  try {
    if (typeof localStorage !== "undefined") {
      const local = localStorage.getItem("krost_pantry_id");
      if (local && local.length > 8) {
        await kvSetString(SHARED_PANTRY_KEY, local);
        return local;
      }
    }
  } catch (e) {}

  // создаём pantry один раз
  try {
    const createUrls = [
      "https://getpantry.cloud/apiv1/pantry",
      `https://corsproxy.io/?${encodeURIComponent("https://getpantry.cloud/apiv1/pantry")}`,
    ];
    for (const createUrl of createUrls) {
      try {
        const r = await fetch(createUrl, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: "manzshop_orders_v3",
            description: "Shared orders for manzshop mini app",
          }),
        });
        if (r.ok) {
          const data = await r.json();
          const id = data?.pantryId || data?.id || null;
          if (id) {
            try {
              if (typeof localStorage !== "undefined") localStorage.setItem("krost_pantry_id", id);
            } catch (e) {}
            await kvSetString(SHARED_PANTRY_KEY, id);
            console.log("[Orders] created pantry", id);
            return id;
          }
        }
      } catch (e) {}
    }
  } catch (e) {
    console.warn("ensurePantryId create", e);
  }

  const again = await kvGetString(SHARED_PANTRY_KEY);
  if (again) return again;
  return null;
};

const compactOrder = (o) => ({
  id: o.id,
  date: o.date,
  status: o.status || "Новый",
  fullName: o.fullName || "",
  phone: o.phone || "",
  address: (o.address || "").slice(0, 140),
  finalTotal: o.finalTotal,
  usedBonus: Number(o.usedBonus) || 0,
  delivery: o.delivery || "courier",
  trackingNumber: o.trackingNumber || null,
  tgId: o.tgId || null,
  tgUsername: o.tgUsername || null,
  freeDelivery: !!o.freeDelivery,
  pendingCashback: Number(o.pendingCashback) || 0,
  cashbackCredited: !!o.cashbackCredited,
  askReview: !!o.askReview,
  reviewDone: !!o.reviewDone,
  utmSource: o.utmSource || null,
  items: (o.items || []).slice(0, 6).map((i) => ({
    id: i.id,
    name: i.name,
    brand: i.brand,
    size: i.size,
    price: i.price,
  })),
});

const ultraCompactOrder = (o) => ({
  id: o.id,
  date: o.date,
  status: o.status || "Новый",
  fullName: (o.fullName || "").slice(0, 40),
  phone: o.phone || "",
  address: (o.address || "").slice(0, 60),
  finalTotal: o.finalTotal,
  delivery: o.delivery || "courier",
  tgId: o.tgId || null,
  tgUsername: o.tgUsername || null,
  utmSource: o.utmSource || null,
  items: (o.items || []).slice(0, 2).map((i) => ({
    name: i.name,
    size: i.size,
    price: i.price,
  })),
});

const pantryBasketUrls = (pantryId, basket) => {
  const base = `https://getpantry.cloud/apiv1/pantry/${pantryId}/basket/${basket}`;
  return [
    base,
    `https://corsproxy.io/?${encodeURIComponent(base)}`,
    `https://api.allorigins.win/raw?url=${encodeURIComponent(base)}`,
  ];
};

// Таймаут для сетевых запросов (чтобы Pantry не блокировал загрузку приложения)
const withTimeout = (promise, ms = 4000) => {
  let timer;
  return Promise.race([
    promise,
    new Promise((_, reject) => {
      timer = setTimeout(() => reject(new Error("timeout")), ms);
    }),
  ]).finally(() => clearTimeout(timer));
};

const pantryGetBasket = async (basket) => {
  try {
    const pantryId = await withTimeout(ensurePantryId(), 3500);
    if (!pantryId) return null;
    for (const url of pantryBasketUrls(pantryId, basket)) {
      try {
        const r = await withTimeout(
          fetch(url, { cache: "no-store", mode: "cors" }),
          4000
        );
        if (!r.ok) continue;
        const data = await r.json();
        return data;
      } catch (e) {}
    }
  } catch (e) {}
  return null;
};

const pantryPutBasket = async (basket, payload) => {
  try {
    const pantryId = await withTimeout(ensurePantryId(), 3500);
    if (!pantryId) return false;
    for (const url of pantryBasketUrls(pantryId, basket)) {
      for (const method of ["PUT", "POST"]) {
        try {
          const r = await withTimeout(
            fetch(url, {
              method,
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify(payload),
            }),
            5000
          );
          if (r.ok) return true;
        } catch (e) {}
      }
    }
  } catch (e) {}
  return false;
};

// ==============================
// Персональные данные пользователя в shared storage
// CloudStorage Telegram НЕ синхронизируется между Desktop и Mobile —
// поэтому корзина/избранное/бонусы пишем на Netlify (как заказы) + fallback.
// ==============================
const userStateBasket = (tgId) => `u_${String(tgId || "").replace(/[^0-9]/g, "")}`;
const userStateKvKey = (tgId) => `ustate_${String(tgId || "").replace(/[^0-9]/g, "")}`;

// Компактная версия корзины/избранного (без base64-картинок)
const compactCartItem = (i) => ({
  id: i.id,
  name: i.name,
  brand: i.brand,
  price: i.price,
  oldPrice: i.oldPrice || null,
  size: i.size || null,
  image: typeof i.image === "string" && i.image.startsWith("data:") ? "" : (i.image || ""),
});

const getUserStateApiUrls = () => {
  const urls = [];
  try {
    if (typeof window !== "undefined" && window.location?.origin) {
      const origin = window.location.origin;
      // functions path first ( /api/* redirect may 404 for new functions )
      urls.push(`${origin}/.netlify/functions/userstate`);
      urls.push(`${origin}/api/userstate`);
    }
  } catch (e) {}
  return urls;
};

const loadUserStateFromShared = async (tgId) => {
  if (!tgId || String(tgId) === "guest" || !/^\d+$/.test(String(tgId))) return null;

  const candidates = [];

  // 1) Netlify — основной надёжный канал
  try {
    const body = JSON.stringify({ action: "get", id: String(tgId) });
    for (const url of getUserStateApiUrls()) {
      try {
        const r = await fetch(url, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body,
          cache: "no-store",
        });
        const data = await r.json().catch(() => ({}));
        if (r.ok && data && data.ok && data.state && typeof data.state === "object") {
          candidates.push(data.state);
          console.log("[UserState] netlify load OK", tgId, {
            cart: (data.state.cart || []).length,
            fav: (data.state.favorites || []).length,
          });
          break;
        }
      } catch (e) {
        console.warn("[UserState] netlify load fail", url, e && e.message);
      }
    }
  } catch (e) {}

  // 2) keyvalue fallback
  try {
    const raw = await kvGetString(userStateKvKey(tgId));
    if (raw) {
      const data = JSON.parse(raw);
      if (data && typeof data === "object") {
        candidates.push(data);
        console.log("[UserState] kv load OK", tgId);
      }
    }
  } catch (e) {}

  // 3) Pantry fallback
  try {
    const data = await pantryGetBasket(userStateBasket(tgId));
    if (data && typeof data === "object" && (data.cart || data.favorites || data.updatedAt)) {
      candidates.push(data);
      console.log("[UserState] pantry load OK", tgId);
    }
  } catch (e) {}

  if (!candidates.length) return null;

  candidates.sort((a, b) => {
    const ta = Date.parse(a.updatedAt || 0) || 0;
    const tb = Date.parse(b.updatedAt || 0) || 0;
    return tb - ta;
  });
  return candidates[0];
};

const saveUserStateToShared = async (tgId, state) => {
  if (!tgId || String(tgId) === "guest" || !/^\d+$/.test(String(tgId))) return false;

  const payload = {
    cart: Array.isArray(state.cart) ? state.cart.map(compactCartItem) : [],
    favorites: Array.isArray(state.favorites) ? state.favorites.map(compactCartItem) : [],
    bonusBalance: Number(state.bonusBalance) || 0,
    orderHistory: Array.isArray(state.orderHistory) ? state.orderHistory.slice(0, 30) : [],
    referralCount: Number(state.referralCount) || 0,
    referralEarnings: Number(state.referralEarnings) || 0,
    orders: Number(state.orders) || 0,
    updatedAt: state.updatedAt || new Date().toISOString(),
  };

  let ok = false;

  // 1) Netlify — главный канал
  try {
    const body = JSON.stringify({
      action: "set",
      id: String(tgId),
      state: payload,
    });
    for (const url of getUserStateApiUrls()) {
      try {
        const r = await fetch(url, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body,
          cache: "no-store",
        });
        const data = await r.json().catch(() => ({}));
        if (r.ok && data && data.ok) {
          ok = true;
          console.log("[UserState] netlify save OK", tgId, "cart", payload.cart.length, "fav", payload.favorites.length);
          break;
        }
        // Сохраняем текст ошибки для тоста
        payload.__lastError = data?.error || data?.detail || `HTTP ${r.status}`;
        console.warn("[UserState] netlify save response", url, r.status, data);
      } catch (e) {
        payload.__lastError = (e && e.message) || String(e);
        console.warn("[UserState] netlify save fail", url, e && e.message);
      }
    }
  } catch (e) {}

  // 2) keyvalue backup
  try {
    const compact = {
      cart: payload.cart.map((x) => ({ ...x, image: (x.image || "").slice(0, 80) })),
      favorites: payload.favorites.map((x) => ({ ...x, image: (x.image || "").slice(0, 80) })),
      bonusBalance: payload.bonusBalance,
      updatedAt: payload.updatedAt,
    };
    const json = JSON.stringify(compact);
    if (json.length <= 1400) {
      const kvOk = await kvSetString(userStateKvKey(tgId), json);
      if (kvOk) ok = true;
    }
  } catch (e) {}

  // 3) Pantry backup
  try {
    const pantryOk = !!(await pantryPutBasket(userStateBasket(tgId), payload));
    if (pantryOk) ok = true;
  } catch (e) {}

  return ok;
};

// Глобальный epoch для принудительного сброса данных у ВСЕХ пользователей
const APP_META_BASKET = "app_meta_v1";
const loadResetEpoch = async () => {
  try {
    const meta = await pantryGetBasket(APP_META_BASKET);
    if (meta && typeof meta.resetEpoch === "number") return meta.resetEpoch;
  } catch (e) {}
  return 0;
};
const bumpResetEpoch = async () => {
  let current = 0;
  try {
    const meta = await pantryGetBasket(APP_META_BASKET);
    if (meta && typeof meta.resetEpoch === "number") current = meta.resetEpoch;
  } catch (e) {}
  const next = current + 1;
  await pantryPutBasket(APP_META_BASKET, {
    resetEpoch: next,
    resetAt: new Date().toISOString(),
  });
  return next;
};

// Загрузка: индекс ID → каждый заказ; + pantry; + старый bulk-ключ
const sharedOrdersLoad = async () => {
  // 0) Netlify API — основной канал
  try {
    const fromApi = await netlifyOrdersLoad();
    if (Array.isArray(fromApi)) {
      return fromApi.sort((a, b) => {
        const da = a.date ? new Date(a.date).getTime() : 0;
        const db = b.date ? new Date(b.date).getTime() : 0;
        return db - da;
      });
    }
  } catch (e) {}

  const map = new Map();

  // A) индекс + отдельные ключи (fallback)
  try {
    const idxRaw = await kvGetString(ORDER_INDEX_KEY);
    if (idxRaw) {
      const ids = String(idxRaw)
        .split(",")
        .map((s) => s.trim())
        .filter(Boolean)
        .slice(0, 50);
      for (const id of ids) {
        try {
          const raw = await kvGetString(orderItemKey(id));
          if (!raw) continue;
          const obj = JSON.parse(raw);
          if (obj && obj.id != null) map.set(String(obj.id), obj);
        } catch (e) {}
      }
    }
  } catch (e) {
    console.warn("sharedOrdersLoad index", e);
  }

  // B) pantry
  try {
    const data = await pantryGetBasket("orders");
    const list = Array.isArray(data) ? data : data && Array.isArray(data.orders) ? data.orders : [];
    list.forEach((o) => {
      if (o && o.id != null && !map.has(String(o.id))) map.set(String(o.id), o);
    });
  } catch (e) {}

  // C) старый bulk KV
  try {
    const raw = await kvGetString(SHARED_ORDERS_KEY);
    if (raw) {
      let parsed = JSON.parse(raw);
      if (typeof parsed === "string") parsed = JSON.parse(parsed);
      const list = Array.isArray(parsed) ? parsed : parsed && Array.isArray(parsed.orders) ? parsed.orders : [];
      list.forEach((o) => {
        if (o && o.id != null && !map.has(String(o.id))) map.set(String(o.id), o);
      });
    }
  } catch (e) {}

  const orders = Array.from(map.values()).sort((a, b) => {
    const da = a.date ? new Date(a.date).getTime() : 0;
    const db = b.date ? new Date(b.date).getTime() : 0;
    return db - da;
  });
  console.log("[Orders] shared load", orders.length);
  return orders;
};

const sharedOrdersSave = async (orders) => {
  const list = (Array.isArray(orders) ? orders : []).slice(0, 50).map(compactOrder);
  let anyOk = false;

  // пишем каждый заказ + индекс
  const ids = list.map((o) => String(o.id));
  const idxOk = await kvSetString(ORDER_INDEX_KEY, ids.join(","));
  if (idxOk) anyOk = true;

  for (const o of list.slice(0, 30)) {
    let raw = JSON.stringify(o);
    if (raw.length > 1400) raw = JSON.stringify(ultraCompactOrder(o));
    if (raw.length > 1400) continue;
    const ok = await kvSetString(orderItemKey(o.id), raw);
    if (ok) anyOk = true;
  }

  // pantry best-effort
  const okPantry = await pantryPutBasket("orders", {
    orders: list,
    updatedAt: new Date().toISOString(),
  });
  if (okPantry) anyOk = true;

  console.log("[Orders] shared save", anyOk ? "OK" : "FAIL", list.length, "pantry", okPantry);
  return anyOk;
};

const sharedOrdersPush = async (order) => {
  try {
    const c = compactOrder(order);
    // Netlify first
    const okNetlify = await netlifyOrdersPushOne(c);
    if (okNetlify) {
      console.log("[Orders] shared push netlify OK", c.id);
      return [c];
    }

    let raw = JSON.stringify(c);
    if (raw.length > 1400) raw = JSON.stringify(ultraCompactOrder(c));

    // 1) сам заказ (главное)
    const okItem = raw.length <= 1500 ? await kvSetString(orderItemKey(c.id), raw) : false;

    // 2) индекс: prepend id
    let ids = [];
    try {
      const idxRaw = await kvGetString(ORDER_INDEX_KEY);
      if (idxRaw) ids = String(idxRaw).split(",").map((s) => s.trim()).filter(Boolean);
    } catch (e) {}
    ids = [String(c.id), ...ids.filter((x) => x !== String(c.id))].slice(0, 50);
    const okIdx = await kvSetString(ORDER_INDEX_KEY, ids.join(","));

    // 3) pantry — подтягиваем текущие и мержим
    try {
      const current = await sharedOrdersLoad();
      const without = current.filter((o) => String(o.id) !== String(c.id));
      const next = [c, ...without].slice(0, 50);
      await pantryPutBasket("orders", { orders: next, updatedAt: new Date().toISOString() });
    } catch (e) {}

    const ok = okItem || okIdx;
    console.log("[Orders] shared push", ok ? "OK" : "FAIL", c.id, "item", okItem, "idx", okIdx);
    return ok ? [c] : null;
  } catch (e) {
    console.warn("sharedOrdersPush", e);
    return null;
  }
};

const sharedOrdersUpdate = async (orderId, patch) => {
  try {
    const okNetlify = await netlifyOrdersPatch(orderId, patch);
    if (okNetlify) {
      console.log("[Orders] patch netlify OK", orderId, patch);
      return true;
    }
    // fallback: полная перезапись списка на Netlify (с админ-секретом)
    const list = await sharedOrdersLoad();
    const merged = (list || []).map((o) =>
      String(o.id) === String(orderId) ? { ...o, ...patch } : o
    );
    const has = merged.some((o) => String(o.id) === String(orderId));
    if (!has) merged.unshift({ id: orderId, ...patch });
    const okSave = await netlifyOrdersSave(merged);
    console.log("[Orders] patch via full save", okSave, orderId);
    return !!okSave;
  } catch (e) {
    console.warn("sharedOrdersUpdate", e);
    return false;
  }
};

// Разбор текста #ORD#...#END# (из пуша / буфера обмена)
const parseOrderFromText = (text) => {
  if (!text) return null;
  const m = String(text).match(/#ORD#([\s\S]*?)#END#/);
  if (!m) return null;
  try {
    const obj = JSON.parse(m[1]);
    if (obj && obj.id != null) return obj;
  } catch (e) {}
  return null;
};

// ----- Общий каталог товаров (виден всем пользователям / устройствам) -----
// ==============================
// ОБЩИЙ КАТАЛОГ — Netlify Function + Blobs (основное хранилище)
// URL: /api/catalog  или  /.netlify/functions/catalog
// Старые fallback (jsonblob/KV) оставлены на всякий случай.
// ==============================
const PRODUCT_INDEX_KEY = "mp3_idx";
const PRODUCT_BLOB_META_KEY = "manzshop_prod_blob_v4";
const productItemKey = (id) => `mp3_${id}`;

const getCatalogApiUrls = () => {
  const urls = [];
  try {
    if (typeof window !== "undefined" && window.location && window.location.origin) {
      const origin = window.location.origin;
      if (origin && !origin.startsWith("file:")) {
        urls.push(`${origin}/api/catalog`);
        urls.push(`${origin}/.netlify/functions/catalog`);
      }
    }
  } catch (e) {}
  return urls;
};

const getOrdersApiUrls = () => {
  const urls = [];
  try {
    if (typeof window !== "undefined" && window.location && window.location.origin) {
      const origin = window.location.origin;
      if (origin && !origin.startsWith("file:")) {
        urls.push(`${origin}/api/orders`);
        urls.push(`${origin}/.netlify/functions/orders`);
      }
    }
  } catch (e) {}
  return urls;
};

const netlifyOrdersLoad = async () => {
  for (const url of getOrdersApiUrls()) {
    try {
      const r = await fetch(url, { method: "GET", cache: "no-store" });
      if (!r.ok) continue;
      const data = await r.json();
      if (data && Array.isArray(data.orders)) {
        console.log("[Orders] netlify load OK", data.orders.length, url);
        return data.orders;
      }
    } catch (e) {}
  }
  return null;
};

const netlifyOrdersSave = async (orders) => {
  const body = JSON.stringify({ orders: (orders || []).slice(0, 80) });
  for (const url of getOrdersApiUrls()) {
    try {
      const r = await fetch(url, {
        method: "POST",
        headers: adminHeaders(),
        body,
        cache: "no-store",
      });
      const data = await r.json().catch(() => ({}));
      if (r.ok && data && data.ok !== false) {
        console.log("[Orders] netlify save OK", data.count, url);
        return true;
      }
    } catch (e) {}
  }
  return false;
};

const netlifyOrdersPushOne = async (order) => {
  const body = JSON.stringify({ order });
  for (const url of getOrdersApiUrls()) {
    try {
      const r = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body,
        cache: "no-store",
      });
      const data = await r.json().catch(() => ({}));
      if (r.ok && data && data.ok !== false) return true;
    } catch (e) {}
  }
  return false;
};


const getUsersApiUrls = () => {
  const urls = [];
  try {
    if (typeof window !== "undefined" && window.location && window.location.origin) {
      const origin = window.location.origin;
      if (origin && !origin.startsWith("file:")) {
        urls.push(`${origin}/api/users`);
        urls.push(`${origin}/.netlify/functions/users`);
      }
    }
  } catch (e) {}
  return urls;
};

const registerBotUser = async (u) => {
  if (!u || !u.id || String(u.id) === "guest") return false;
  if (!/^\d+$/.test(String(u.id))) return false;
  const body = JSON.stringify({
    action: "register",
    id: String(u.id),
    username: u.username || "",
    first_name: u.first_name || u.name || "",
    last_name: u.last_name || "",
  });
  for (const url of getUsersApiUrls()) {
    try {
      const r = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body,
        cache: "no-store",
      });
      const data = await r.json().catch(() => ({}));
      if (r.ok && data && data.ok) {
        console.log("[Users] registered", u.id, "count", data.count);
        return data;
      }
    } catch (e) {}
  }
  return false;
};

/**
 * Telegram не даёт подставить /start за пользователя.
 * Но можно:
 * 1) requestWriteAccess — системный запрос «разрешить боту писать»
 * 2) один раз предложить открыть чат с ботом (t.me/...?start=app)
 */
const ensureBotMessagingAccess = async (u) => {
  try {
    await registerBotUser(u);

    const tgWeb =
      typeof window !== "undefined" &&
      window.Telegram &&
      window.Telegram.WebApp
        ? window.Telegram.WebApp
        : null;
    if (!tgWeb) return;

    const storageKey = "krost_write_access_asked";
    let alreadyAsked = false;
    try {
      alreadyAsked = localStorage.getItem(storageKey) === "1";
    } catch (e) {}

    // 1) Официальный запрос права писать пользователю (Bot API 6.9+)
    if (typeof tgWeb.requestWriteAccess === "function" && !alreadyAsked) {
      try {
        localStorage.setItem(storageKey, "1");
      } catch (e) {}
      await new Promise((resolve) => {
        try {
          tgWeb.requestWriteAccess((granted) => {
            console.log("[TG] requestWriteAccess", granted);
            resolve(!!granted);
          });
        } catch (e) {
          resolve(false);
        }
      });
      return;
    }

    // 2) Fallback: один раз открыть бота со start-параметром
    // (пользователь сам нажимает Start в чате)
    const startKey = "krost_bot_start_opened";
    let startOpened = false;
    try {
      startOpened = localStorage.getItem(startKey) === "1";
    } catch (e) {}
    if (!startOpened && typeof tgWeb.openTelegramLink === "function") {
      try {
        localStorage.setItem(startKey, "1");
      } catch (e) {}
      // Не форсим каждый раз — только если write access API нет
      if (typeof tgWeb.requestWriteAccess !== "function") {
        try {
          tgWeb.openTelegramLink("https://t.me/manzshop_bot?start=fromapp");
        } catch (e) {}
      }
    }
  } catch (e) {
    console.warn("ensureBotMessagingAccess", e);
  }
};

