  // Приводит фото к 1000×1000, белый фон, кроссовок по центру
  const processProductImage = (dataUrl) =>
    new Promise((resolve) => {
      try {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.onload = () => {
          try {
            const SIZE = 1000;
            const canvas = document.createElement("canvas");
            canvas.width = SIZE;
            canvas.height = SIZE;
            const ctx = canvas.getContext("2d");
            // белый фон
            ctx.fillStyle = "#FFFFFF";
            ctx.fillRect(0, 0, SIZE, SIZE);
            // вписать с отступами ~10%
            const pad = SIZE * 0.1;
            const maxW = SIZE - pad * 2;
            const maxH = SIZE - pad * 2;
            const scale = Math.min(maxW / img.width, maxH / img.height);
            const w = img.width * scale;
            const h = img.height * scale;
            const x = (SIZE - w) / 2;
            const y = (SIZE - h) / 2;
            ctx.drawImage(img, x, y, w, h);

            // Осветляем почти-белый / серый фон → чисто белый
            // (помогает для студийных фото; сложный фон улицы не уберёт)
            try {
              const imageData = ctx.getImageData(0, 0, SIZE, SIZE);
              const d = imageData.data;
              for (let i = 0; i < d.length; i += 4) {
                const r = d[i];
                const g = d[i + 1];
                const b = d[i + 2];
                const maxc = Math.max(r, g, b);
                const minc = Math.min(r, g, b);
                const avg = (r + g + b) / 3;
                // светлый и малонасыщенный пиксель → белый
                if (avg > 210 && maxc - minc < 35) {
                  d[i] = 255;
                  d[i + 1] = 255;
                  d[i + 2] = 255;
                } else if (avg > 235) {
                  d[i] = 255;
                  d[i + 1] = 255;
                  d[i + 2] = 255;
                }
              }
              ctx.putImageData(imageData, 0, 0);
            } catch (e) {}

            const out = canvas.toDataURL("image/jpeg", 0.9);
            resolve(out || dataUrl);
          } catch (e) {
            resolve(dataUrl);
          }
        };
        img.onerror = () => resolve(dataUrl);
        img.src = dataUrl;
      } catch (e) {
        resolve(dataUrl);
      }
    });

  // Скачать картинку по URL и привести к 1000×1000 (для импорта из таблицы)
  const processImageFromUrl = async (url) => {
    if (!url || !/^https?:\/\//i.test(url)) return url;
    const candidates = [
      url,
      `https://corsproxy.io/?${encodeURIComponent(url)}`,
      `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`,
    ];
    for (const src of candidates) {
      try {
        const r = await fetch(src, { cache: "no-store", mode: "cors" });
        if (!r.ok) continue;
        const blob = await r.blob();
        if (!blob || !String(blob.type || "").startsWith("image/")) continue;
        const dataUrl = await new Promise((res, rej) => {
          const reader = new FileReader();
          reader.onload = () => res(String(reader.result || ""));
          reader.onerror = rej;
          reader.readAsDataURL(blob);
        });
        if (!dataUrl) continue;
        return await processProductImage(dataUrl);
      } catch (e) {}
    }
    return url; // если не удалось — оставляем исходную ссылку
  };

  const pickProductImage = (onPicked) => {
    try {
      if (typeof document === "undefined") {
        Alert.alert("Ошибка", "Загрузка фото доступна в Telegram / браузере");
        return;
      }
      const input = document.createElement("input");
      input.type = "file";
      input.accept = "image/*";
      input.onchange = async (e) => {
        const file = e.target?.files?.[0];
        if (!file) return;
        if (file.size > 8 * 1024 * 1024) {
          Alert.alert("Файл слишком большой", "Максимум 8 МБ.");
          return;
        }
        showToast("Обрабатываю фото…");
        const reader = new FileReader();
        reader.onload = async () => {
          const raw = String(reader.result || "");
          const dataUrl = await processProductImage(raw);
          updateProductDraft("image", dataUrl);
          if (typeof onPicked === "function") onPicked(dataUrl);
          showToast("✅ Фото готово 1000×1000");
        };
        reader.readAsDataURL(file);
      };
      input.click();
    } catch (err) {
      console.warn("pickProductImage", err);
      Alert.alert("Ошибка", "Не удалось открыть выбор файла");
    }
  };

  // draftOverride — чтобы сохранять из локальной формы AdminPanel без гонки setState
  const saveProductDraft = (draftOverride, isNewOverride) => {
    const draft = draftOverride || productDraft;
    const makingNew = typeof isNewOverride === "boolean" ? isNewOverride : isNewProduct;
    if (!draft) return;
    const brand = (draft.brand || "").trim() || "Бренд";
    const name = (draft.name || "").trim() || "Товар";
    const price = parseInt(String(draft.price).replace(/\D/g, ""), 10) || 0;
    const oldRaw = String(draft.oldPrice || "").replace(/\D/g, "");
    const oldPrice = oldRaw ? parseInt(oldRaw, 10) : null;
    let images = Array.isArray(draft.images)
      ? draft.images.map((u) => String(u || "").trim()).filter(Boolean)
      : [];
    // если в поле image вручную вставили URL — добавим
    const single = (draft.image || "").trim();
    if (single && !images.includes(single)) {
      // если images пустой — single главный; если есть — single может быть устаревшим первым
      if (!images.length) images = [single];
    }
    if (!images.length) images = ["https://via.placeholder.com/400?text=Photo"];
    const image = images[0];
    const description = (draft.description || "").trim();
    const sizes = String(draft.sizes || "")
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
    if (!name || name === "Товар") {
      // если пользователь ничего не ввёл — всё равно сохраняем, но предупреждаем
      console.warn("[Product] name empty, using placeholder");
    }
    if (!price) {
      Alert.alert("Цена", "Укажите цену товара");
      return;
    }
    const payload = {
      brand,
      name,
      price,
      oldPrice,
      image,
      images,
      description,
      sizes: sizes.length ? sizes : ["40", "41", "42"],
    };
    let nextProducts = null;
    if (makingNew) {
      nextProducts = [
        {
          id: draft.id,
          ...payload,
          sales: 0,
          ratings: [],
          averageRating: 0,
          createdAt: new Date().toISOString(),
          pinned: false,
        },
        ...products,
      ];
      setProducts(nextProducts);
    } else {
      nextProducts = products.map((p) => (p.id === draft.id ? { ...p, ...payload } : p));
      setProducts(nextProducts);
    }
    setEditingProduct(null);
    setProductDraft(null);
    setIsNewProduct(false);

    const hasDataImage = getProductImages(payload).some((u) => String(u).startsWith("data:"));
    // Публикуем в ОБЩЕЕ хранилище (все устройства + все пользователи)
    (async () => {
      let ok = false;
      for (let attempt = 0; attempt < 3 && !ok; attempt++) {
        ok = await sharedProductsSave(nextProducts);
        if (!ok) await new Promise((r) => setTimeout(r, 400 * (attempt + 1)));
      }
      if (!ok) {
        console.warn("[Products] shared save failed");
        showToast("⚠️ Товар локально. Общее сохранение не удалось — повторите");
      } else if (hasDataImage) {
        showToast("✅ Сохранено. Для всех устройств лучше URL фото, не файл");
      } else {
        showToast("✅ Товар виден на всех устройствах");
      }
    })();
  };

