  const Catalog = () => {

    const brands = getBrands(products);
    const allSizes = Array.from(
      new Set(
        (products || []).flatMap((p) =>
          (Array.isArray(p.sizes) ? p.sizes : []).map((s) => String(s).trim()).filter(Boolean)
        )
      )
    ).sort((a, b) => Number(a) - Number(b) || String(a).localeCompare(String(b)));
    const { theme } = useTheme();
    const isDark = theme === "dark";

    // Локальный стейт поиска — чтобы клавиатура не закрывалась
    const [localSearch, setLocalSearch] = useState(searchQuery);
    const [localMin, setLocalMin] = useState(minPrice);
    const [localMax, setLocalMax] = useState(maxPrice);
    const [localBrand, setLocalBrand] = useState(selectedBrand);
    const [localSize, setLocalSize] = useState(null); // фильтр по размеру
    const [sortBy, setSortBy] = useState(null); // null | "asc" | "desc"
    const [onlyNew, setOnlyNew] = useState(false);   // Новинки (3 дня)
    const [onlySale, setOnlySale] = useState(false); // Скидки (есть oldPrice)
    const [filtersOpen, setFiltersOpen] = useState(false);
    const [localPage, setLocalPage] = useState(1);
    const [localLoading, setLocalLoading] = useState(false);

    const threeDaysAgo = Date.now() - 3 * 24 * 60 * 60 * 1000;

    // Фильтруем и сортируем локально
    let localFiltered = products.filter(p => {
      if (p.hidden) return false; // скрытые админом — не показываем в каталоге
      const q = localSearch.toLowerCase();
      const matchName = (p.name || "").toLowerCase().includes(q) || (p.brand || "").toLowerCase().includes(q);
      const matchBrand = localBrand ? p.brand === localBrand : true;
      const matchSize = localSize
        ? (Array.isArray(p.sizes) ? p.sizes : []).map(String).includes(String(localSize))
        : true;
      const matchPrice = (localMin === "" || p.price >= parseInt(localMin)) && (localMax === "" || p.price <= parseInt(localMax));
      const matchNew = !onlyNew || (p.createdAt && new Date(p.createdAt).getTime() >= threeDaysAgo);
      const matchSale = !onlySale || (p.oldPrice != null && Number(p.oldPrice) > Number(p.price));
      return matchName && matchBrand && matchSize && matchPrice && matchNew && matchSale;
    });

    // Сортировка: сначала закреплённые, потом по цене (если выбрано)
    localFiltered = [...localFiltered].sort((a, b) => {
      const pinA = a.pinned ? 1 : 0;
      const pinB = b.pinned ? 1 : 0;
      if (pinB !== pinA) return pinB - pinA;
      if (sortBy === "asc") return a.price - b.price;
      if (sortBy === "desc") return b.price - a.price;
      return 0;
    });

    const LOCAL_PAGE_SIZE = 4;
    const localPaginated = localFiltered.slice(0, localPage * LOCAL_PAGE_SIZE);
    const localHasMore = localPaginated.length < localFiltered.length;

    const activeFiltersCount =
      (localBrand ? 1 : 0) +
      (localSize ? 1 : 0) +
      (sortBy ? 1 : 0) +
      (localMin !== "" || localMax !== "" ? 1 : 0) +
      (onlyNew ? 1 : 0) +
      (onlySale ? 1 : 0);

    const handleSearchChange = (text) => {
      setLocalSearch(text);
      setLocalPage(1);
    };
    const handleLoadMore = () => {
      if (localLoading || !localHasMore) return;
      setLocalLoading(true);
      setTimeout(() => {
        setLocalPage(prev => prev + 1);
        setLocalLoading(false);
      }, 400);
    };
    const resetFilters = () => {
      setLocalBrand(null);
      setSelectedBrand(null);
      setLocalSize(null);
      setLocalMin("");
      setLocalMax("");
      setSortBy(null);
      setOnlyNew(false);
      setOnlySale(false);
      setLocalPage(1);
    };
    const applyFilters = () => {
      setSelectedBrand(localBrand);
      setMinPrice(localMin);
      setMaxPrice(localMax);
      setLocalPage(1);
      setFiltersOpen(false);
    };

    // Данные для секций макета
    const visible = (products || []).filter((p) => !p.hidden);
    const threeDays = Date.now() - 3 * 24 * 60 * 60 * 1000;
    const novinki = [...visible]
      .filter((p) => p.createdAt && new Date(p.createdAt).getTime() >= threeDays)
      .sort((a, b) => (b.pinned ? 1 : 0) - (a.pinned ? 1 : 0))
      .slice(0, 8);
    const novinkiList = novinki.length ? novinki : visible.slice(0, 8);
    const popular = [...visible]
      .sort((a, b) => {
        if (!!b.pinned !== !!a.pinned) return (b.pinned ? 1 : 0) - (a.pinned ? 1 : 0);
        return (Number(b.averageRating) || 0) - (Number(a.averageRating) || 0);
      })
      .slice(0, 8);
    const brandList = brands.length ? brands : ["Nike", "Jordan", "Adidas", "New Balance"];

    const openProduct = (item) => {
      setSelectedProduct(item);
      setSelectedSize(null);
      setPage("product");
    };

    const HorizCard = ({ item }) => {
      const isFav = favorites.some((x) => x.id === item.id);
      return (
        <TouchableOpacity activeOpacity={0.9} onPress={() => openProduct(item)} style={styles.horizCard}>
          <View style={{ position: "relative" }}>
            <SmartImage uri={getProductMainImage(item)} style={styles.horizCardImg} resizeMode="contain" />
            <TouchableOpacity
              style={[styles.favoriteBtn, isFav && styles.favoriteBtnActive, { top: 6, right: 6 }]}
              onPress={(e) => { e?.stopPropagation?.(); toggleFavorite(item); }}
            >
              <Text style={[styles.favoriteBtnText, isFav && styles.favoriteBtnTextActive]}>{isFav ? "♥" : "♡"}</Text>
            </TouchableOpacity>
          </View>
          <Text style={styles.horizCardName} numberOfLines={2}>{item.name}</Text>
          <Text style={styles.horizCardPrice}>{money(item.price)}</Text>
        </TouchableOpacity>
      );
    };

    const showSections = !localSearch && activeFiltersCount === 0;

    return (
      <View style={[styles.page, styles.catalogPage, isDark && styles.pageDark]}>
        <TextInput
          style={[styles.searchInput, styles.catalogSearch, isDark && styles.inputDark]}
          placeholder="Поиск кроссовок"
          placeholderTextColor={isDark ? "#999" : "#888"}
          value={localSearch}
          onChangeText={handleSearchChange}
          blurOnSubmit={false}
          autoCorrect={false}
          autoCapitalize="none"
          returnKeyType="search"
        />

        <TouchableOpacity
          style={[styles.filterChip, styles.filterChipActive, { alignSelf: "flex-start", marginBottom: 14, paddingHorizontal: 18 }]}
          onPress={() => setFiltersOpen(true)}
          activeOpacity={0.8}
        >
          <Text style={styles.filterChipTextActive}>
            Фильтры{activeFiltersCount > 0 ? ` · ${activeFiltersCount}` : ""}
          </Text>
        </TouchableOpacity>

        <Modal visible={filtersOpen} transparent animationType="fade" onRequestClose={() => setFiltersOpen(false)}>
          <View style={styles.modalOverlay}>
            <View style={[styles.modalView, isDark && styles.modalViewDark, { maxHeight: "85%" }]}>
              <Text style={[styles.modalTitle, isDark && styles.textDark]}>Фильтры</Text>
              <Text style={[styles.sizeTitle, isDark && styles.textDark, { marginBottom: 8 }]}>Сортировка</Text>
              <View style={{ flexDirection: "row", flexWrap: "wrap", marginBottom: 16 }}>
                {[{ key: null, label: "По умолчанию" }, { key: "asc", label: "Цена ↑" }, { key: "desc", label: "Цена ↓" }].map((opt) => (
                  <TouchableOpacity key={String(opt.key)} style={[styles.filterChip, sortBy === opt.key && styles.filterChipActive, { marginBottom: 6 }]} onPress={() => setSortBy(opt.key)}>
                    <Text style={sortBy === opt.key ? styles.filterChipTextActive : null}>{opt.label}</Text>
                  </TouchableOpacity>
                ))}
              </View>
              <Text style={[styles.sizeTitle, isDark && styles.textDark, { marginBottom: 8 }]}>Категория</Text>
              <View style={{ flexDirection: "row", flexWrap: "wrap", marginBottom: 16 }}>
                <TouchableOpacity style={[styles.filterChip, onlyNew && styles.filterChipActive, { marginBottom: 6 }]} onPress={() => setOnlyNew((v) => !v)}>
                  <Text style={onlyNew ? styles.filterChipTextActive : null}>Новинки</Text>
                </TouchableOpacity>
                <TouchableOpacity style={[styles.filterChip, onlySale && styles.filterChipActive, { marginBottom: 6 }]} onPress={() => setOnlySale((v) => !v)}>
                  <Text style={onlySale ? styles.filterChipTextActive : null}>Скидки</Text>
                </TouchableOpacity>
              </View>
              <Text style={[styles.sizeTitle, isDark && styles.textDark, { marginBottom: 8 }]}>Бренд</Text>
              <View style={{ flexDirection: "row", flexWrap: "wrap", marginBottom: 16 }}>
                <TouchableOpacity style={[styles.filterChip, localBrand === null && styles.filterChipActive, { marginBottom: 6 }]} onPress={() => setLocalBrand(null)}>
                  <Text style={localBrand === null ? styles.filterChipTextActive : null}>Все</Text>
                </TouchableOpacity>
                {brands.map((b) => (
                  <TouchableOpacity key={b} style={[styles.filterChip, localBrand === b && styles.filterChipActive, { marginBottom: 6 }]} onPress={() => setLocalBrand(b)}>
                    <Text style={localBrand === b ? styles.filterChipTextActive : null}>{b}</Text>
                  </TouchableOpacity>
                ))}
              </View>
              <Text style={[styles.sizeTitle, isDark && styles.textDark, { marginBottom: 8 }]}>Размер</Text>
              <View style={{ flexDirection: "row", flexWrap: "wrap", marginBottom: 16 }}>
                <TouchableOpacity style={[styles.filterChip, localSize === null && styles.filterChipActive, { marginBottom: 6 }]} onPress={() => setLocalSize(null)}>
                  <Text style={localSize === null ? styles.filterChipTextActive : null}>Все</Text>
                </TouchableOpacity>
                {allSizes.map((s) => (
                  <TouchableOpacity key={s} style={[styles.filterChip, localSize === s && styles.filterChipActive, { marginBottom: 6, minWidth: 44 }]} onPress={() => setLocalSize(s)}>
                    <Text style={localSize === s ? styles.filterChipTextActive : null}>{s}</Text>
                  </TouchableOpacity>
                ))}
              </View>
              <Text style={[styles.sizeTitle, isDark && styles.textDark, { marginBottom: 8 }]}>Цена</Text>
              <View style={styles.priceFilter}>
                <TextInput style={[styles.priceInput, isDark && styles.inputDark]} placeholder="от" placeholderTextColor={isDark ? "#999" : "#888"} value={localMin} onChangeText={setLocalMin} keyboardType="numeric" blurOnSubmit={false} />
                <TextInput style={[styles.priceInput, isDark && styles.inputDark]} placeholder="до" placeholderTextColor={isDark ? "#999" : "#888"} value={localMax} onChangeText={setLocalMax} keyboardType="numeric" blurOnSubmit={false} />
              </View>
              <View style={styles.modalButtons}>
                <TouchableOpacity style={styles.modalCancel} onPress={resetFilters}><Text>Сбросить</Text></TouchableOpacity>
                <TouchableOpacity style={styles.modalConfirm} onPress={applyFilters}><Text style={{ color: "#fff", fontWeight: "700" }}>Применить</Text></TouchableOpacity>
              </View>
            </View>
          </View>
        </Modal>

        {showSections ? (
          <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={{ paddingBottom: 24 }}>
            <View style={styles.sectionHeaderRow}>
              <Text style={styles.sectionHeader}>НОВИНКИ</Text>
              <TouchableOpacity onPress={() => setOnlyNew(true)}>
                <Text style={styles.sectionLink}>Смотреть все</Text>
              </TouchableOpacity>
            </View>
            <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={{ paddingRight: 8 }}>
              {novinkiList.map((item) => (
                <HorizCard key={"new-" + item.id} item={item} />
              ))}
            </ScrollView>

            <View style={[styles.sectionHeaderRow, { marginTop: 22 }]}>
              <Text style={styles.sectionHeader}>КАТЕГОРИИ</Text>
              <TouchableOpacity onPress={() => setFiltersOpen(true)}>
                <Text style={styles.sectionLink}>Все</Text>
              </TouchableOpacity>
            </View>
            <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={{ paddingRight: 8, paddingVertical: 4 }}>
              {brandList.map((b) => (
                <TouchableOpacity key={b} style={styles.brandCircleWrap} onPress={() => { setLocalBrand(b); setSelectedBrand(b); }} activeOpacity={0.85}>
                  <View style={styles.brandCircle}>
                    <Text style={styles.brandCircleLetter}>{(b || "?").charAt(0)}</Text>
                  </View>
                  <Text style={styles.brandCircleLabel} numberOfLines={1}>{b}</Text>
                </TouchableOpacity>
              ))}
            </ScrollView>

            <View style={[styles.sectionHeaderRow, { marginTop: 22 }]}>
              <Text style={styles.sectionHeader}>ПОПУЛЯРНОЕ</Text>
              <Text style={styles.sectionLink}>Все</Text>
            </View>
            <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={{ paddingRight: 8 }}>
              {popular.map((item) => (
                <HorizCard key={"pop-" + item.id} item={item} />
              ))}
            </ScrollView>
          </ScrollView>
        ) : (
          <FlatList
            data={localPaginated}
            renderItem={({ item }) => <ProductCard item={item} />}
            keyExtractor={(item) => item.id.toString()}
            numColumns={2}
            columnWrapperStyle={styles.grid}
            contentContainerStyle={{ paddingBottom: 20 }}
            onEndReached={handleLoadMore}
            onEndReachedThreshold={0.5}
            keyboardShouldPersistTaps="handled"
            ListFooterComponent={localLoading ? <Text style={[styles.loader, isDark && styles.textDark]}>Загрузка...</Text> : null}
            ListEmptyComponent={
              <View style={{ paddingVertical: 40, alignItems: "center" }}>
                <Text style={[styles.empty, isDark && styles.textDark]}>
                  {!dataReady ? "Загружаю каталог…" : "Товаров нет"}
                </Text>
              </View>
            }
          />
        )}
      </View>
    );
  };

  // ---- ProductPage ----
  const ProductPage = () => {
    if (!selectedProduct) return null;
    const { theme } = useTheme(); 
    const isDark = theme === "dark";
    const [rating, setRating] = useState(0);
    const [comment, setComment] = useState("");
    const [openDesc, setOpenDesc] = useState(false);
    const [openDelivery, setOpenDelivery] = useState(false);
    const [openSizeTable, setOpenSizeTable] = useState(false);
    const hasPurchased = orderHistory.some(order => order.items.some(i => i.id === selectedProduct.id));

    const handleAddToCart = () => {
      if (!selectedSize) {
        showToast("⚠️ Выберите размер");
        return;
      }
      // В корзину + сразу убрать из избранного одним сохранением
      const item = { ...selectedProduct, size: selectedSize };
      const nextCart = [...(cartRef.current || []), item];
      const nextFav = (favoritesRef.current || []).filter(
        (x) => String(x.id) !== String(selectedProduct.id)
      );
      cartRef.current = nextCart;
      favoritesRef.current = nextFav;
      setCart(nextCart);
      setFavorites(nextFav);
      persistUserState({ cart: nextCart, favorites: nextFav }, { force: true }).catch(() => {});
      showToast(`✅ ${selectedProduct.name} добавлен в корзину`);
    };

    const submitRating = () => {
      if (rating === 0) { 
        Alert.alert("Ошибка", "Поставьте оценку"); 
        return; 
      }
      addRating(selectedProduct.id, rating, comment);
      setRating(0); 
      setComment("");
      Alert.alert("Спасибо", "Отзыв добавлен");
    };

    const isFav = favorites.some(x => x.id === selectedProduct.id);

    return (
      <ScrollView style={[styles.page, isDark && styles.pageDark]} contentContainerStyle={styles.scrollContent}>
        <View style={styles.productHeader}>
          <TouchableOpacity style={styles.headerBtn} onPress={() => setPage("catalog")}>
            <Text style={styles.headerBtnText}>‹</Text>
          </TouchableOpacity>

          <TouchableOpacity style={styles.headerBtn} onPress={() => shareProduct(selectedProduct)}>
            <Text style={styles.headerBtnText}>↗</Text>
          </TouchableOpacity>
        </View>

        {(() => {
          const gallery = getProductImages(selectedProduct);
          const imgs = gallery.length ? gallery : ["https://via.placeholder.com/400?text=Photo"];
          const screenW =
            typeof window !== "undefined" && window.innerWidth
              ? window.innerWidth
              : 360;
          // ширина слайда = экран минус горизонтальные отступы страницы
          const slideW = Math.max(260, screenW - 32);
          return (
            <View style={styles.bigImageWrap}>
              {imgs.length === 1 ? (
                <SmartImage uri={imgs[0]} style={styles.bigImage} highQuality resizeMode="contain" />
              ) : (
                <ScrollView
                  horizontal
                  pagingEnabled
                  showsHorizontalScrollIndicator={false}
                  decelerationRate="fast"
                  snapToInterval={slideW}
                  snapToAlignment="start"
                  style={{ width: "100%" }}
                  contentContainerStyle={{ alignItems: "center" }}
                >
                  {imgs.map((uri, idx) => (
                    <SmartImage
                      key={`${selectedProduct.id}-img-${idx}`}
                      uri={uri}
                      style={[styles.bigImage, { width: slideW, height: slideW, aspectRatio: 1 }]}
                      highQuality
                      resizeMode="contain"
                    />
                  ))}
                </ScrollView>
              )}
              {imgs.length > 1 && (
                <View style={{ flexDirection: "row", justifyContent: "center", gap: 6, marginTop: 8 }}>
                  {imgs.map((_, idx) => (
                    <View
                      key={`dot-${idx}`}
                      style={{
                        width: 7,
                        height: 7,
                        borderRadius: 4,
                        backgroundColor: "#111",
                        opacity: 0.35,
                      }}
                    />
                  ))}
                </View>
              )}
              <TouchableOpacity
                style={[styles.favoriteBtn, styles.favoriteBtnOnImage, isFav && styles.favoriteBtnActive]}
                onPress={() => {
                  toggleFavorite(selectedProduct);
                  showToast(isFav ? "Удалено из избранного" : "❤️ Добавлено в избранное");
                }}
              >
                <Text style={[styles.favoriteBtnText, isFav && styles.favoriteBtnTextActive]}>{isFav ? "♥" : "♡"}</Text>
              </TouchableOpacity>
            </View>
          );
        })()}
        
        <View style={styles.productTitleRow}>
          <View style={{ flex: 1, paddingRight: 12 }}>
            <Text style={[styles.productTitle, isDark && styles.textDark]}>{selectedProduct.name}</Text>
            <Text style={[styles.productBrand, isDark && styles.textDark, { marginTop: 2 }]}>
              {selectedProduct.brand || ""}
            </Text>
          </View>
          <View style={{ alignItems: "flex-end" }}>
            {selectedProduct.oldPrice ? (
              <Text style={styles.oldPriceBig}>{money(selectedProduct.oldPrice)}</Text>
            ) : null}
            <Text style={[styles.productPrice, isDark && styles.textDark]}>{money(selectedProduct.price)}</Text>
          </View>
        </View>

        <View style={styles.sizeBox}>
          <View style={styles.sizeHeaderRow}>
            <Text style={[styles.sizeTitle, isDark && styles.textDark]}>РАЗМЕР</Text>
            <TouchableOpacity onPress={() => setOpenSizeTable((v) => !v)}>
              <Text style={styles.sizeTableLink}>Таблица размеров</Text>
            </TouchableOpacity>
          </View>
          <View style={styles.sizes}>
            {(selectedProduct.sizes || ["40", "41", "42", "43", "44", "45"]).map((size) => (
              <TouchableOpacity
                key={size}
                style={[styles.size, selectedSize === size && styles.sizeActive]}
                onPress={() => setSelectedSize(size)}
              >
                <Text style={selectedSize === size ? styles.sizeTextActive : styles.sizeText}>{size}</Text>
              </TouchableOpacity>
            ))}
          </View>
          {openSizeTable && (
            <View style={styles.sizeTable}>
              <View style={styles.sizeTableHead}>
                <Text style={styles.sizeTableHeadCell}>EU</Text>
                <Text style={styles.sizeTableHeadCell}>см (стопа)</Text>
                <Text style={styles.sizeTableHeadCell}>US</Text>
                <Text style={styles.sizeTableHeadCell}>UK</Text>
              </View>
              {[
                { eu: "40", cm: "25.5", us: "7", uk: "6" },
                { eu: "41", cm: "26.0", us: "8", uk: "7" },
                { eu: "42", cm: "26.5", us: "8.5", uk: "7.5" },
                { eu: "43", cm: "27.5", us: "9.5", uk: "8.5" },
                { eu: "44", cm: "28.0", us: "10", uk: "9" },
                { eu: "45", cm: "29.0", us: "11", uk: "10" },
              ].map((row) => (
                <View key={row.eu} style={styles.sizeTableRow}>
                  <Text style={styles.sizeTableCell}>{row.eu}</Text>
                  <Text style={styles.sizeTableCell}>{row.cm}</Text>
                  <Text style={styles.sizeTableCell}>{row.us}</Text>
                  <Text style={styles.sizeTableCell}>{row.uk}</Text>
                </View>
              ))}
            </View>
          )}
        </View>

        <TouchableOpacity activeOpacity={0.88} onPress={handleAddToCart} style={styles.brushBtnWrapWide}>
          <Image source={{ uri: BRUSH_BTN_URI }} style={styles.brushBtnImgWide} resizeMode="stretch" />
          <Text style={[styles.brushBtnTextOverlay, { fontSize: 14, letterSpacing: 0.4 }]}>ДОБАВИТЬ В КОРЗИНУ</Text>
        </TouchableOpacity>

        {/* Accordion: ОПИСАНИЕ */}
        <TouchableOpacity style={styles.accRow} onPress={() => setOpenDesc((v) => !v)} activeOpacity={0.7}>
          <Text style={styles.accTitle}>ОПИСАНИЕ</Text>
          <Text style={styles.accPlus}>{openDesc ? "−" : "+"}</Text>
        </TouchableOpacity>
        {openDesc && (
          <Text style={styles.accBody}>
            {selectedProduct.description ||
              "Описания пока не добавили :("}
          </Text>
        )}

        {/* Accordion: ДОСТАВКА И ВОЗВРАТ */}
        <TouchableOpacity style={styles.accRow} onPress={() => setOpenDelivery((v) => !v)} activeOpacity={0.7}>
          <Text style={styles.accTitle}>ДОСТАВКА И ВОЗВРАТ</Text>
          <Text style={styles.accPlus}>{openDelivery ? "−" : "+"}</Text>
        </TouchableOpacity>
        {openDelivery && (
          <Text style={styles.accBody}>
            Мы доставляем курьером и почтой по всей Беларуси с оплатой при получении.{"\n\n"}
            При доставке курьером у вас будет время на примерку перед оплатой.{"\n\n"}
            Обмен в случае неподходящего размера возможен в течение 14 дней после получения.{"\n"}
            Возврат — в течение 30 дней после получения.
          </Text>
        )}

        <Text style={[styles.sectionTitle, isDark && styles.textDark]}>Отзывы</Text>
        {(() => {
          const approvedReviews = (selectedProduct.ratings || []).filter(r => r.approved === true);
          return approvedReviews.length > 0 ? (
            approvedReviews.slice(0, 5).map((r, idx) => (
              <View key={idx} style={[styles.reviewItem, isDark && styles.reviewItemDark]}>
                <Text style={[styles.reviewRating, isDark && styles.textDark]}>{"★".repeat(r.rating)}</Text>
                <Text style={[styles.reviewComment, isDark && styles.textDark]}>{r.comment}</Text>
                {r.adminReply ? (
                  <Text style={[styles.reviewComment, isDark && styles.textDark, { marginTop: 4, fontStyle: "italic", color: "#555" }]}>
                    Ответ магазина: {r.adminReply}
                  </Text>
                ) : null}
                <Text style={[styles.reviewDate, isDark && styles.textDark]}>{new Date(r.date).toLocaleDateString()}</Text>
              </View>
            ))
          ) : (
            <Text style={[styles.noReviews, isDark && styles.textDark]}>Пока нет отзывов</Text>
          );
        })()}

        {hasPurchased && (
          <View style={[styles.reviewForm, isDark && styles.reviewFormDark]}>
            <Text style={[styles.reviewFormTitle, isDark && styles.textDark]}>Оставить отзыв</Text>
            <View style={styles.stars}>
              {[1,2,3,4,5].map(s => (
                <TouchableOpacity key={s} onPress={() => setRating(s)}>
                  <Text style={[
                    styles.star,
                    rating >= s
                      ? (isDark ? styles.starActiveDark : styles.starActive)
                      : styles.starInactive
                  ]}>{rating >= s ? "★" : "☆"}</Text>
                </TouchableOpacity>
              ))}
            </View>
            <TextInput style={[styles.reviewInput, isDark && styles.inputDark]} placeholder="Ваш комментарий..." placeholderTextColor={isDark ? "#999" : "#888"} value={comment} onChangeText={setComment} blurOnSubmit={false} />
            <TouchableOpacity style={styles.submitReview} onPress={submitRating}>
              <Text style={styles.buttonText}>Отправить</Text>
            </TouchableOpacity>
          </View>
        )}
        <View style={{ height: 20 }} />
      </ScrollView>
    );
  };

  // ---- Favorites ----
  const Favorites = () => {
    const { theme } = useTheme();
    const isDark = theme === "dark";
    return (
      <ScrollView style={[styles.page, isDark && styles.pageDark]} contentContainerStyle={styles.scrollContent}>
        <Text style={[styles.pageTitle, styles.listPageTitle, isDark && styles.textDark]}>ИЗБРАННОЕ</Text>
        {favorites.length === 0 ? (
          <Text style={[styles.empty, isDark && styles.textDark]}>Нет сохраненных товаров</Text>
        ) : (
          favorites.map((item) => (
            <TouchableOpacity
              key={item.id}
              style={styles.listRow}
              activeOpacity={0.85}
              onPress={() => {
                setSelectedProduct(item);
                setSelectedSize(null);
                setPage("product");
              }}
            >
              <SmartImage uri={getProductMainImage(item)} style={styles.listRowImg} resizeMode="contain" />
              <View style={{ flex: 1, paddingRight: 8 }}>
                <Text style={styles.listRowName} numberOfLines={2}>{item.name}</Text>
                <Text style={styles.listRowPrice}>{money(item.price)}</Text>
              </View>
              <TouchableOpacity onPress={() => toggleFavorite(item)} hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}>
                <Text style={{ fontSize: 22, color: "#111" }}>♥</Text>
              </TouchableOpacity>
            </TouchableOpacity>
          ))
        )}
        <View style={{ height: 20 }} />
      </ScrollView>
    );
  };

  // ---- Cart ----
  const SWIPE_W = 160; // 80 fav + 80 delete

  const SwipeableCartItem = ({ item, idx, isDark }) => {
    const translateX = React.useRef(new Animated.Value(0)).current;
    const offsetX = React.useRef(0);
    const isFav = favorites.some(x => x.id === item.id);

    const panResponder = React.useRef(
      PanResponder.create({
        onMoveShouldSetPanResponder: (_, g) =>
          Math.abs(g.dx) > 10 && Math.abs(g.dx) > Math.abs(g.dy) * 1.2,
        onPanResponderGrant: () => {
          translateX.stopAnimation((v) => {
            offsetX.current = v;
          });
        },
        onPanResponderMove: (_, g) => {
          const next = Math.min(0, Math.max(-SWIPE_W, offsetX.current + g.dx));
          translateX.setValue(next);
        },
        onPanResponderRelease: (_, g) => {
          translateX.stopAnimation((v) => {
            const open = v < -SWIPE_W / 2 || g.vx < -0.6;
            const to = open ? -SWIPE_W : 0;
            Animated.spring(translateX, {
              toValue: to,
              useNativeDriver: true,
              tension: 90,
              friction: 14,
            }).start();
            offsetX.current = to;
          });
        },
        onPanResponderTerminate: () => {
          Animated.spring(translateX, {
            toValue: offsetX.current < -SWIPE_W / 2 ? -SWIPE_W : 0,
            useNativeDriver: true,
            tension: 90,
            friction: 14,
          }).start();
        },
      })
    ).current;

    const closeSwipe = () => {
      Animated.spring(translateX, {
        toValue: 0,
        useNativeDriver: true,
        tension: 90,
        friction: 14,
      }).start();
      offsetX.current = 0;
    };

    const handleFav = () => {
      toggleFavorite(item);
      showToast(isFav ? "Удалено из избранного" : "❤️ Добавлено в избранное");
      closeSwipe();
    };

    const handleDelete = () => {
      removeCart(idx);
    };

    return (
      <View style={styles.swipeContainer}>
        <View style={styles.swipeActions}>
          <TouchableOpacity style={styles.swipeFavBtn} onPress={handleFav} activeOpacity={0.85}>
            <Text style={styles.swipeFavIcon}>{isFav ? "♥" : "♡"}</Text>
            <Text style={styles.swipeFavLabel}>В избранное</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.swipeDelBtn} onPress={handleDelete} activeOpacity={0.85}>
            <Text style={styles.swipeDelIcon}>✕</Text>
            <Text style={styles.swipeDelLabel}>Удалить</Text>
          </TouchableOpacity>
        </View>
        <Animated.View
          style={[
            styles.cartItem,
            isDark && styles.cartItemDark,
            { transform: [{ translateX }], marginBottom: 0 },
          ]}
          {...panResponder.panHandlers}
        >
          <SmartImage uri={item.image} style={styles.cartImage} />
          <View style={{ flex: 1 }}>
            <Text style={[styles.productName, isDark && styles.textDark]}>{item.name}</Text>
            {item.size && <Text style={[styles.sizeText, isDark && styles.textDark]}>Размер: {item.size}</Text>}
            {!item.size && <Text style={[styles.sizeText, { color: "red" }]}>⚠️ Размер не выбран</Text>}
            <Text style={[styles.price, isDark && styles.textDark]}>{money(item.price)}</Text>
          </View>
        </Animated.View>
      </View>
    );
  };

